<?php if (!defined('ABSPATH')) exit; ?>
<div class="wrap sc-admin"><h1>Tarifs</h1><form method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>"><input type="hidden" name="action" value="shakass_save_pricing"><?php wp_nonce_field('shakass_save_pricing'); ?><section class="sc-card"><h2>Prix de base par produit</h2><?php foreach($products as $p): ?><label><?php echo esc_html($p['name']); ?><input type="number" step="0.01" name="pricing[base][<?php echo esc_attr($p['slug']); ?>]" value="<?php echo esc_attr((string)($pricing['base'][$p['slug']] ?? 0)); ?>"></label><?php endforeach; ?></section><section class="sc-card"><h2>Formats et options</h2><div class="sc-admin-grid"><?php foreach(['A7','A6','A5','A4','A3'] as $f): ?><label><?php echo $f; ?><input type="number" step="0.01" name="pricing[formats][<?php echo $f; ?>]" value="<?php echo esc_attr((string)$pricing['formats'][$f]); ?>"></label><?php endforeach; ?><label>Coût texte<input name="pricing[text]" type="number" step="0.01" value="<?php echo esc_attr((string)$pricing['text']); ?>"></label><label>Coût logo/image<input name="pricing[image]" type="number" step="0.01" value="<?php echo esc_attr((string)$pricing['image']); ?>"></label><label>Coût QR code<input name="pricing[qr]" type="number" step="0.01" value="<?php echo esc_attr((string)$pricing['qr']); ?>"></label></div></section><section class="sc-card"><h2>Remises quantité (%)</h2><?php foreach(['1-9','10-24','25-49','50+'] as $r): ?><label><?php echo esc_html($r); ?><input name="pricing[discounts][<?php echo esc_attr($r); ?>]" type="number" step="0.01" value="<?php echo esc_attr((string)$pricing['discounts'][$r]); ?>"></label><?php endforeach; ?></section><button class="button button-primary">Enregistrer les tarifs</button></form></div>
